import React from "react";

function MenuItem({ name, description, price }) {
  return (
    <div className="MenuItem">
      <h3>{name}</h3>
      <p>
        {description}
        <br />
        Price: ${price}
      </p>
    </div>
  );
}

export default MenuItem;
